        if (n % 2 == 0) {
            long long aa = llabs(a), bb = llabs(b);
            if (aa > bb) res = 1;
            else if (aa < bb) res = 2;
            else res = 0;
        } else {
            if (a > b) res = 1;
            else if (a < b) res = 2;
            else res = 0;
        }
        printf("%d\n", res);
    }
    return 0;
}

