import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it)); n = int(next(it))
        if n % 2 == 0:
            aa = abs(a); bb = abs(b)
            if aa > bb:
                out.append('1')
            elif aa < bb:
                out.append('2')
            else:
                out.append('0')
        else:
            if a > b:
                out.append('1')
            elif a < b:
                out.append('2')
            else:
                out.append('0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

